import { writeOutput } from "./codegen";

const DOCS_URL = "https://docs.n8n.io/api/api-reference/";
// n8n API keys are prefixed n8n_api_ followed by a 32-char alphanumeric string
const PLACEHOLDER_VALUE = "n8n_api_CoffeeSafeLocalCoffeeSafeLocalCo";

function generateTypeScript(): string {
  const lines: string[] = [
    "// Auto-generated from n8n REST API docs.",
    `// Source: ${DOCS_URL}`,
    "// Regenerate: cd turbo && pnpm -F @vm0/firewalls-generator generate:n8n",
    "//",
    "// DO NOT EDIT THIS FILE MANUALLY.",
    "",
    'import type { FirewallConfig } from "../firewall-types";',
    "",
    "export const n8nFirewall = {",
    '  name: "n8n",',
    '  description: "n8n REST API",',
    "  placeholders: {",
    `    N8N_TOKEN: "${PLACEHOLDER_VALUE}",`,
    "  },",
    "  apis: [",
    "    {",
    '      base: "${{ vars.N8N_BASE_URL }}/api/v1",',
    "      auth: {",
    "        headers: {",
    '          "X-N8N-API-KEY": "${{ secrets.N8N_TOKEN }}",',
    "        },",
    "      },",
    "      permissions: [],",
    "    },",
    "  ],",
    "} as const satisfies FirewallConfig;",
    "",
  ];
  return lines.join("\n");
}

export async function generate(): Promise<void> {
  console.error("Generating n8n firewall config...");
  const ts = generateTypeScript();
  writeOutput("n8n", ts, import.meta.dirname);
}
